"use client";

import { useState, useEffect, Fragment } from "react";
import { MITM_TOOLS } from "@/shared/constants/cliTools";
import { getModelsByProviderId } from "@/shared/constants/models";
import { isOpenAICompatibleProvider, isAnthropicCompatibleProvider } from "@/shared/constants/providers";
import { MitmServerCard, MitmToolCard, TokenSwapPoolCard } from "@/app/(dashboard)/dashboard/cli-tools/components";

export default function MitmPageClient() {
  const [connections, setConnections] = useState([]);
  const [apiKeys, setApiKeys] = useState([]);
  const [modelAliases, setModelAliases] = useState({});
  const [cloudEnabled, setCloudEnabled] = useState(false);
  const [expandedTool, setExpandedTool] = useState(null);
  const [mitmStatus, setMitmStatus] = useState({ running: false, certExists: false, dnsStatus: {}, hasCachedPassword: false });
  const [tokenSwapActive, setTokenSwapActive] = useState(false);

  const fetchConnections = async () => {
    try {
      const res = await fetch("/api/providers");
      if (res.ok) {
        const data = await res.json();
        setConnections(data.connections || []);
      }
    } catch { /* ignore */ }
  };

  const fetchApiKeys = async () => {
    try {
      const res = await fetch("/api/keys");
      if (res.ok) {
        const data = await res.json();
        setApiKeys(data.keys || []);
      }
    } catch { /* ignore */ }
  };

  const fetchAliases = async () => {
    try {
      const res = await fetch("/api/models/alias");
      if (res.ok) {
        const data = await res.json();
        setModelAliases(data.aliases || {});
      }
    } catch { /* ignore */ }
  };

  const fetchCloudSettings = async () => {
    try {
      const res = await fetch("/api/settings");
      if (res.ok) {
        const data = await res.json();
        setCloudEnabled(data.cloudEnabled || false);
        setTokenSwapActive(!!data.tokenSwapEnabled);
      }
    } catch { /* ignore */ }
  };

  useEffect(() => {
    const loadInitialData = async () => {
      await Promise.all([
        fetchConnections(),
        fetchApiKeys(),
        fetchAliases(),
        fetchCloudSettings(),
      ]);
    };

    loadInitialData();
  }, []);

  const getActiveProviders = () => connections.filter(c => c.isActive !== false);

  const hasActiveProviders = () => {
    const active = getActiveProviders();
    return active.some(conn =>
      getModelsByProviderId(conn.provider).length > 0 ||
      isOpenAICompatibleProvider(conn.provider) ||
      isAnthropicCompatibleProvider(conn.provider)
    );
  };

  const mitmTools = Object.entries(MITM_TOOLS);

  return (
    <div className="mx-auto flex w-full max-w-5xl flex-col gap-6 px-1 sm:px-0">
      <div className="flex flex-col gap-1">
        <h1 className="text-xl font-semibold text-text-main sm:text-2xl">MITM</h1>
        <p className="text-sm text-text-muted">Route supported IDE traffic through xscope0 Modifed with local DNS interception.</p>
      </div>

      {/* MITM Server Card */}
      <MitmServerCard
        apiKeys={apiKeys}
        cloudEnabled={cloudEnabled}
        onStatusChange={setMitmStatus}
      />

      {/* Tool Cards */}
      <div className="grid gap-3 sm:gap-4">
        {mitmTools.map(([toolId, tool]) => (
          <Fragment key={toolId}>
            <MitmToolCard
              tool={tool}
              isExpanded={expandedTool === toolId}
              onToggle={() => setExpandedTool(expandedTool === toolId ? null : toolId)}
              serverRunning={mitmStatus.running}
              dnsActive={mitmStatus.dnsStatus?.[toolId] || false}
              hasCachedPassword={mitmStatus.hasCachedPassword || false}
              apiKeys={apiKeys}
              activeProviders={getActiveProviders()}
              hasActiveProviders={hasActiveProviders()}
              modelAliases={modelAliases}
              cloudEnabled={cloudEnabled}
              tokenSwapActive={tool.supportsTokenSwap && tokenSwapActive}
              onDnsChange={(data) => setMitmStatus(prev => ({ ...prev, dnsStatus: data.dnsStatus ?? prev.dnsStatus }))}
            />
            {tool.supportsTokenSwap && (
              <TokenSwapPoolCard
                tool={tool}
                connections={connections}
                serverRunning={mitmStatus.running}
                dnsActive={mitmStatus.dnsStatus?.[toolId] || false}
                onToggle={(val) => setTokenSwapActive(val)}
                onRefreshConnections={fetchConnections}
              />
            )}
          </Fragment>
        ))}
      </div>
    </div>
  );
}
